<template>
  <div :style="{ marginLeft: indent + 'px' }">
    <v-checkbox
      v-model="isChecked"
      :label="localSection.label"
      :color="localSection.color || 'primary'"
      :disabled="!parentChecked"
      @change="onCheckboxChange"
    />

    <!-- Smaller Collapse/Expand Button -->
    <v-btn
      v-if="localSection.children && localSection.children.length > 0"
      @click="toggleCollapse"
      icon
      class="collapse-btn" 
    >
      <v-icon small>{{ localSection.collapsed ? 'mdi-chevron-right' : 'mdi-chevron-down' }}</v-icon>
    </v-btn>

    <div v-if="localSection.children && localSection.children.length > 0 && !localSection.collapsed">
      <SectionCheckbox
        v-for="child in localSection.children"
        :key="child.id"
        :section="child"
        :indent="indent + 20"
        :parent-checked="isChecked"
        :all-collapsed="allCollapsed"
        @update-checked="emitUpdateChecked"
      />
    </div>
  </div>
</template>

<script>
export default {
  name: 'SectionCheckbox',
  props: {
    section: Object,
    indent: {
      type: Number,
      default: 0,
    },
    parentChecked: {
      type: Boolean,
      default: true,
    },
    allCollapsed: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      isChecked: this.section.checked,
      localSection: { ...this.section }, // Create a local copy
    };
  },
  watch: {
    'section.checked': {
      immediate: true,
      handler(newVal) {
        this.isChecked = newVal;
      },
    },
    'section.color': {
      immediate: true,
      handler(newVal) {
        this.localSection.color = newVal; // Update color when prop changes
      },
    },
    allCollapsed: {
      immediate: true,
      handler(newVal) {
        this.localSection.collapsed = newVal; // Collapse/expand all sections
      },
    },
    isChecked(newVal) {
      if (!newVal && this.localSection.children) {
        this.localSection.children.forEach((child) => {
          child.checked = false;
        });
      }
    },
  },
  emits: ['update-checked'],
  methods: {
    onCheckboxChange() {
      this.$emit('update-checked', { id: this.localSection.id, checked: this.isChecked });

      if (!this.isChecked && this.localSection.children) {
        this.localSection.children.forEach((child) => {
          child.checked = false;
        });
      }
    },
    toggleCollapse() {
      this.localSection.collapsed = !this.localSection.collapsed; // Toggle collapse
    },
    emitUpdateChecked(payload) {
      this.$emit('update-checked', payload);
    },
  },
};
</script>

<style scoped>
.section-container {
  display: flex;
  align-items: center;
}

.collapse-btn {
  margin-left: 8px; /* Adjust spacing between checkbox and icon */
  padding: 2px; /* Reduce padding for a smaller button */
}

.v-icon {
  font-size: 18px; /* Adjust the icon size */
}
</style>
