<template>
  <v-container>
    <v-card>
      <v-card-title>Upload Document Template</v-card-title>
      <v-card-text>
        <!-- Dropdown for selecting the collection -->
        <v-select
          v-model="selectedCollection"
          :items="collections"
          item-title="displayName"
          item-value="name"
          label="Select Collection"
          placeholder="Select a Category"
          dense
        ></v-select>

        <v-file-input
          v-model="selectedFile"
          label="Select Document Template"
          accept=".docx"
          prepend-icon="mdi-file-document"
        ></v-file-input>

        <v-text-field
          v-model="version"
          label="Enter Version"
          placeholder="e.g., 1.0"
        ></v-text-field>

        <v-btn
          :disabled="!selectedFile || !version || !selectedCollection"
          color="blue-grey-darken-2"
          @click="uploadFile"
        >
          Upload
        </v-btn>
      </v-card-text>
    </v-card>

    <!-- Snackbar for status messages -->
    <v-snackbar
      v-model="snackbar.show"
      :timeout="snackbar.timeout"
      :color="snackbar.color"
      top
      right
    >
      {{ snackbar.message }}
    </v-snackbar>
  </v-container>
</template>

<script>
import axios from 'axios';

export default {
  data() {
    return {
      selectedFile: null,
      version: '',
      selectedCollection: '',
      collections: [], // List of collections
      snackbar: {
        show: false,
        message: '',
        color: '',
        timeout: 3000,
      },
    };
  },
  async mounted() {
  try {
    const response = await axios.get('/api/collections');
    // Filter collections to only show those that meet the criteria
    this.collections = response.data
      .filter((name) => name.startsWith('cat_') && name.endsWith('.files'))
      .map((name) => ({
        name, // Original name (with .files) for sending to the backend
        displayName: name.replace('cat_', '').replace('.files', ''), // User-friendly name (without cat_ and .files)
      }));
    // Add this console log to check filtered collections
    console.log('Filtered collections:', this.collections);
  } catch (error) {
    console.error('Error fetching collections:', error);
  }
},
  methods: {
    async uploadFile() {
      if (!this.selectedFile || !this.version || !this.selectedCollection) {
        this.showSnackbar('Please select a file, version, and collection', 'error');
        return;
      }

      const formData = new FormData();
      formData.append('file', this.selectedFile);
      formData.append('version', this.version);
      formData.append('collectionName', this.selectedCollection);

      try {
        await axios.post('/api/upload-template', formData, {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        });
        this.showSnackbar(`File uploaded successfully to ${this.selectedCollection}. Version: ${this.version}`, 'success');
        this.selectedFile = null;
        this.version = '';
        this.selectedCollection = '';
      } catch (error) {
        console.error('Error uploading file:', error);
        const errorMessage = error.response?.data?.message || 'Failed to upload file';
        this.showSnackbar(errorMessage, 'error');
      }
    },
    showSnackbar(message, color) {
      this.snackbar.message = message;
      this.snackbar.color = color;
      this.snackbar.show = true;
    },
  },
};
</script>
