<template>
  <v-app>
    <!-- Header Wrapper: includes hover-trigger and app bar -->
    <div
      class="header-wrapper"
      @mouseenter="showAppBar"
      @mouseleave="hideAppBarWithDelay"
    >
      <!-- Hover Trigger Area -->
      <div class="hover-trigger"></div>

      <!-- Global App Bar -->
      <v-app-bar
        :class="{ visible: isAppBarVisible }"
        app
        color="blue-grey-lighten-4"
        dark
        class="custom-app-bar"
      >
        <v-toolbar-title class="header-title">Document Status</v-toolbar-title>
        <v-spacer></v-spacer>

        <!-- Notification Buttons -->
        <v-btn icon>
          <v-icon>mdi-clock-outline</v-icon>
        </v-btn>
        <v-btn icon>
          <v-icon>mdi-check-circle-outline</v-icon>
        </v-btn>
        <v-btn icon>
          <v-icon>mdi-close-circle-outline</v-icon>
        </v-btn>

        <!-- Action Buttons -->
        <v-btn @click="goToUploadForApproval">
          <v-icon>mdi-cloud-upload-outline</v-icon>
          Upload for Approval
        </v-btn>
        <v-btn @click="goToIntentRecognitionPage">
          <v-icon>mdi-robot-outline</v-icon>
          Try AI
        </v-btn>
        <v-btn @click="logout">
          <v-icon>mdi-logout</v-icon>
          Logout
        </v-btn>
      </v-app-bar>
    </div>

    <!-- Main Content -->
    <v-main>
      <router-view />
    </v-main>
  </v-app>
</template>

<script>
export default {
  name: 'App',
  data() {
    return {
      isAppBarVisible: false, // Control the visibility of the app bar
      hideTimeout: null,       // Track the timeout for hiding
    };
  },
  methods: {
    // Show the app bar immediately and clear any existing hide timeout
    showAppBar() {
      this.isAppBarVisible = true;
      clearTimeout(this.hideTimeout);
    },
    
    // Hide the app bar after a delay to allow for smooth transition
    hideAppBarWithDelay() {
      this.hideTimeout = setTimeout(() => {
        this.isAppBarVisible = false;
      }, 300); // Delay in milliseconds (adjust as needed)
    },
    
    // Cancel the hide timeout if the user hovers back over the app bar
    cancelHide() {
      clearTimeout(this.hideTimeout);
    },
    
    // Logout function to clear session and redirect to login page
    logout() {
      localStorage.removeItem('jwtToken');
      localStorage.removeItem('username');
      this.$router.replace({ name: 'login' });
    },
    
    // Navigate to Upload for Approval page
    goToUploadForApproval() {
      this.$router.push({ name: 'uploadForApproval' });
    },
    
    // Navigate to Intent Recognition Page
    goToIntentRecognitionPage() {
      this.$router.push({ name: 'intentRecognitionPage' });
    },
  },
};
</script>

